// Get raw Gemini
const rawText = $input.first().json.content.parts[0].text;

if (!rawText) {
  throw new Error("Gemini returned empty text");
}

// Remove markdown fences if present
let cleaned = rawText
  .replace(/```json/gi, "")
  .replace(/```/g, "")
  .trim();

// Extract JSON safely
const match = cleaned.match(/\{[\s\S]*\}/);

if (!match) {
  throw new Error("No valid JSON found in Gemini response");
}

cleaned = match[0];

let parsed;

try {
  parsed = JSON.parse(cleaned);
} catch (err) {
  throw new Error("Invalid JSON from Gemini: " + cleaned.substring(0, 300));
}

// Get previous workflow context
const ctx = $node["7. Merge Avatar URLs + All Data"].json;

// Return structured data for your pipeline
return [{
  json: {
    reelNumber: ctx.reelNumber,
    accountToPost: ctx.accountToPost,
    reelType: ctx.reelType,
    timing: ctx.timing,
    songLink: ctx.songLink,

    lyricalSubtext: parsed.lyrical_subtext || "",
    colorPalette: parsed.color_palette || "",
    identityAnchor: parsed.identity_anchor || "",
    outfitStyling: parsed.styling?.outfit || "",
    lightingStyling: parsed.styling?.lighting || "",
    reference_image_prompt:parsed.reference_image_prompt || "",
    shots: parsed.shots || [],
    totalShots: parsed.shots?.length || 0
  }
}];

const ctx = $node["10. Prepare Nanobana Input"].json;

return [{
  json: ctx,
  binary: $input.first().binary
}];

