  parentId = searchNode.id;
} else {
  const createdNode = $node["Create automation directory in client folder"].json;

  if (!createdNode || !createdNode.id) {
    throw new Error("Parent folder not found and not created.");
  }

  parentId = createdNode.id;
}

return [{
