    parentFolderId: parentId
  }
}];

let parentId;

// Try getting searched folder
const searchNode = $node["Search parent Reel"].json;

if (searchNode && searchNode.id) {
  parentId = searchNode.id;
} else {
  const createdNode = $node["Create Reelfolder"].json;

  if (!createdNode || !createdNode.id) {
    throw new Error("Parent folder not found and not created.");
  }

  parentId = createdNode.id;
}

return [{
  json: {
    parentFolderId: parentId
  }
}];

let ReelId;

// Get search results safely
const searchItems = $node["checking for review image folder exist"].json;

if (searchItems && searchItems.id) {
  ReelId = searchItems.id;
} else {
  const createdItems = $node["Create Review_images Folder"].json;

  if (!createdItems || !createdItems.id) {
    throw new Error("Reelfolder not found and not created.");
  }

  ReelId = createdItems.id;
}

return [{
  json: {
    ReelReviewId: ReelId
  }
}];

// Get avatar data
const data = $items("Merfe for concept and Avatar Data", 0, 0)[0].json;

const avatarNames = data["Avatar Names"];
const urls = data["Reference URLs"];

// Build mapping
const mapping = {};
const image_urls = [];

avatarNames.forEach((name, index) => {
  mapping[name] = `<image:${index}>`;
  image_urls.push(urls[index]);
});

// Current shot
let shotPrompt = $json.StoryShots;
let klingPrompt = shotPrompt;

// Replace placeholders
avatarNames.forEach((name, index) => {

  const placeholder1 = `<<${name}>>`;
  const placeholder2 = `<<${name.replace(/[0-9]/g,"")}>>`; // handles <<Avatar_Female>>

  klingPrompt = klingPrompt.replaceAll(placeholder1, `<image:${index}>`);
  klingPrompt = klingPrompt.replaceAll(placeholder2, `<image:${index}>`);

});

return {
  json: {
    ...$json,
    kling_prompt: klingPrompt,
    image_urls,
    mapping
  }
};
